16	let catalogRevision = 1;
17	let catalogUpdatedAt = new Date();
18	
19	const baseProducts: Omit<Product, 'availability' | 'updatedAt'>[] = [
20	  { id: 'prod_001', sku: 'TSH-ALP-001', name: 'Alpine Trail Tee', category: 'Apparel', price: 34, inventory: 182 },
21	  { id: 'prod_002', sku: 'JCK-ARC-114', name: 'Arc Jacket', category: 'Apparel', price: 128, inventory: 41 },
