24	  { id: 'prod_005', sku: 'BTL-FLD-018', name: 'Field Bottle', category: 'Outdoor', price: 28, inventory: 96 },
25	  { id: 'prod_006', sku: 'SKN-LUM-087', name: 'Lumen Serum', category: 'Beauty', price: 62, inventory: 8 },
26	  { id: 'prod_007', sku: 'SHS-DRV-020', name: 'Drift Sneakers', category: 'Footwear', price: 94, inventory: 67 },
27	  { id: 'prod_008', sku: 'CND-GLW-301', name: 'Glow Candle', category: 'Home', price: 18, inventory: 133 }
28	];
