30	function getAvailability(inventory: number, price: number, revision: number): ProductAvailability {
31	  if (((revision + price) % 17) === 0) {
32	    return 'Discontinued';
33	  }
34	
35	  if (inventory === 0) {
36	    return 'Backorder';
37	  }
38	
39	  if (inventory < 20) {
40	    return 'Low stock';
41	  }
42	
43	  return 'In stock';
44	}
45	
46	function buildCatalogSnapshot(): Product[] {
47	  return baseProducts.map((product, index) => {
48	    const revisionShift = catalogRevision + index;
49	    const inventoryDelta = ((revisionShift * 7) % 13) - 6;
50	    const inventory = Math.max(0, product.inventory + inventoryDelta);
51	    const priceShift = ((revisionShift * 3) % 9) - 4;
52	    const price = Math.max(8, product.price + priceShift);
53	
54	    return {
55	      ...product,
56	      price,
57	      inventory,
58	      availability: getAvailability(inventory, price, revisionShift),
59	      updatedAt: catalogUpdatedAt.toISOString()
60	    };
61	  });
62	}
63	
64	let catalogSnapshot = buildCatalogSnapshot();
65	
66	export async function getProducts() {
67	  'use cache';
68	  cacheTag('products');
69	
70	  return catalogSnapshot;
71	}
72	
73	export async function syncLatestCatalogSnapshot() {
74	  catalogRevision += 1;
75	  catalogUpdatedAt = new Date();
76	  catalogSnapshot = buildCatalogSnapshot();
77	}
